import{l,a,c as e,aj as i}from"./chunks/framework.CyPZ6aEA.js";const S=JSON.parse('{"title":"渲染模式","description":"","frontmatter":{},"headers":[],"relativePath":"blog/frontend/render.md","filePath":"blog/frontend/render.md"}'),o={name:"blog/frontend/render.md"};function r(s,t,h,n,u,c){return a(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="渲染模式" tabindex="-1">渲染模式 <a class="header-anchor" href="#渲染模式" aria-label="Permalink to &quot;渲染模式&quot;">​</a></h1><h2 id="why" tabindex="-1">why <a class="header-anchor" href="#why" aria-label="Permalink to &quot;why&quot;">​</a></h2><p>开发前端项目的时候，需要考虑部署的环境，针对环境，选择何时的页面渲染模式，才能针对性的选择最合适的框架。</p><h2 id="how" tabindex="-1">how <a class="header-anchor" href="#how" aria-label="Permalink to &quot;how&quot;">​</a></h2><p>前端渲染模式的演进过程大致为：</p><ol><li>2010 年之前，传统时代，SSR 服务端渲染。主机部署</li><li>2015 年左右，SPA 时代，CSR 客户端渲染。边缘部署</li><li>2018 年左右，SSR 复兴时代，SSR 水合交互。主机。主机部署</li><li>2018 之后，内容驱动，SSG/JAMStack 静态内容 + 少量交互水合。边缘部署，静态服务</li><li>2018 之后，混合模式，ISR/边缘渲染。边缘部署，可静态可动态服务</li></ol><blockquote><p>简单地理解“边缘”，即最接近用户的服务器节点，最快响应用户，如 CDN</p></blockquote><h3 id="○-ssr" tabindex="-1">○ SSR <a class="header-anchor" href="#○-ssr" aria-label="Permalink to &quot;○ SSR&quot;">​</a></h3><ul><li>输入：用户请求页面</li><li>处理：服务端获取数据 -&gt; 生成 html -&gt; 返回</li><li>输出：用户接收 html -&gt; 渲染</li></ul><h3 id="○-csr" tabindex="-1">○ CSR <a class="header-anchor" href="#○-csr" aria-label="Permalink to &quot;○ CSR&quot;">​</a></h3><ul><li>输入：用户请求页面</li><li>处理：服务端永远返回 index.html（非 hash 模式） -&gt; 客户端加载对应页面 js 进行渲染</li><li>输出：执行 js -&gt; 客户端渲染</li></ul><h3 id="○-ssr-水合" tabindex="-1">○ SSR 水合 <a class="header-anchor" href="#○-ssr-水合" aria-label="Permalink to &quot;○ SSR 水合&quot;">​</a></h3><p>Astro：</p><ul><li>输入：用户请求页面</li><li>处理：服务端获取数据 -&gt; 生成 html，含 js 链接👀 -&gt; 返回</li><li>输出：用户接收 html -&gt; 渲染 -&gt; 加载 js 岛屿 -&gt; 再渲染</li></ul><p>Next.js：</p><ul><li>输入：用户请求页面</li><li>处理：服务端获取数据 -&gt; 生成 html，含 js 链接 -&gt; 返回</li><li>输出：用户接收 html（可选流式，关键内容优先） -&gt; 渲染 -&gt; 加载 js（优先交互中或交互可能性大的） -&gt; 再渲染</li></ul><blockquote><p>Next.js 中有多种水合模式</p></blockquote><h3 id="○-ssg-水合" tabindex="-1">○ SSG 水合 <a class="header-anchor" href="#○-ssg-水合" aria-label="Permalink to &quot;○ SSG 水合&quot;">​</a></h3><p>Astro：</p><ul><li>输入：用户请求页面</li><li>处理：服务端返回预生成的 html，含 js 链接 -&gt; 返回</li><li>输出：用户接收 html -&gt; 渲染 -&gt; 加载 js 岛屿 -&gt; 再渲染</li></ul><blockquote><p>不像 SPA 那样可以便捷地进行全局状态共享。</p></blockquote><h3 id="○-isr" tabindex="-1">○ ISR <a class="header-anchor" href="#○-isr" aria-label="Permalink to &quot;○ ISR&quot;">​</a></h3><p>Next.js：</p><ul><li>输入：用户请求页面</li><li>处理：服务端检查预生成的 html，含 js 链接 -&gt; 页面缓存过期，服务端重新生成 -&gt; 返回</li><li>输出：用户接收 html -&gt; 渲染 -&gt; 加载 js 岛屿 -&gt; 再渲染</li></ul><blockquote><p>Next.js 中通过 getStaticProps 函数返回的 revalidate 缓存时间来判断是否重新生成</p></blockquote><blockquote><p>Astro 借助部署平台来管理缓存</p></blockquote><blockquote><p>Remix 借助 HTTP 缓存头实现</p></blockquote><h2 id="what" tabindex="-1">what <a class="header-anchor" href="#what" aria-label="Permalink to &quot;what&quot;">​</a></h2><p>涉及服务端的边缘部署 -&gt; SSG 水合、ISR -&gt; 可选 Next.js，Astro 等</p><p>不涉及服务端的边缘部署 -&gt; SSG 水合、CSR -&gt; 可选 Next.js，Nuxt.js，Astro，Vite 构建的 SPA 等</p>',30)])])}const p=l(o,[["render",r]]);export{S as __pageData,p as default};
